    'en',
    slug,
    descriptor,
    'The ' || name || ' is a ' || lower(category) || ' with ' || lower(trait_1) || ', ' || lower(trait_2) || ', and ' || lower(trait_3) || '. It belongs to ' || lower(habitat) || ' where those traits help it stay effective.'
